import React from "react";
import Navbar from "./components/Navbar";
import Hero from "./components/Hero";
import Skills from "./components/Skills";
import Projects from "./components/Projects";
import { SectionHeader } from "./components/Skills";

function Contact() {
  return (
    <section id="contact" className="py-24 border-t border-border">
      <div className="max-w-5xl mx-auto px-6">
        <SectionHeader index="03" title="Contact" />
        <div className="mt-12 max-w-md">
          <p className="text-muted text-sm leading-relaxed mb-6">
            Feel free to reach out for collaborations, questions, or just to talk math.
          </p>
          <a
            href="mailto:sasha@example.com"
            className="font-mono text-xs bg-accent text-white px-5 py-2.5 rounded hover:bg-accent/80 transition-colors inline-block"
          >
            sasha@example.com →
          </a>
        </div>
      </div>
    </section>
  );
}

export default function App() {
  return (
    <div className="bg-bg min-h-screen">
      <Navbar />
      <Hero />
      <Skills />
      <Projects />
      <Contact />
    </div>
  );
}
